import type { ExtensionAPI } from "@oh-my-pi/pi-coding-agent";
import * as fs from "node:fs";
import * as path from "node:path";
import * as os from "node:os";
import { execSync } from "node:child_process";

/**
 * Xpert — On-demand expert agent selector + update system
 *
 * /xpert              → interactive category selector → agent selector
 * /xpert list         → list all agents by category
 * /xpert skills       → list all skills
 * /xpert activate <n> → load agent expertise into context
 * /xpert skill <n>    → load skill into context
 * /xpert models       → show model catalog with roles
 * /update-agents check      → check repos for new commits
 * /update-agents pull       → pull changes and adapt new/changed agents
 * /update-agents reconcile  → rewrite agent frontmatter from models.yml roles
 * /update-skills check      → check composio repo for new skills
 * /update-skills pull       → pull new skills and adapt them
 */

const CATEGORY_LABELS: Record<string, string> = {
	dev: "Core Development",
	lang: "Language Specialists",
	infra: "Infrastructure",
	qual: "Quality & Security",
	data: "Data & AI",
	dx: "Developer Experience",
	spec: "Specialized Domains",
	biz: "Business & Product",
	meta: "Meta-Orchestration",
	res: "Research & Analysis",
};

const CATEGORY_ORDER = [
	"dev", "lang", "infra", "qual", "data",
	"dx", "spec", "biz", "meta", "res",
];

interface AgentMeta {
	name: string;
	description: string;
	category: string;
	role: string;
	model: string;
	filePath: string;
}

interface SkillMeta {
	name: string;
	description: string;
	dir: string;
}

interface RepoState {
	url: string;
	commit: string;
	date: string;
}

interface Manifest {
	sources: Record<string, RepoState & { agents: string[]; skills: string[] }>;
}

function getAgentsDir(): string {
	return path.join(os.homedir(), ".omp", "agent", "agents");
}

function getSkillsDir(): string {
	return path.join(os.homedir(), ".omp", "agent", "skills");
}

function getModelsYml(): string {
	return path.join(os.homedir(), ".omp", "agent", "models.yml");
}

function getRoleMapYml(): string {
	return path.join(os.homedir(), ".omp", "agent", "role-map.yml");
}

function getManifestYml(): string {
	return path.join(os.homedir(), ".omp", "agent", "manifest.yml");
}

function parseSimpleYaml(filepath: string): Record<string, Record<string, string>> {
	const result: Record<string, Record<string, string>> = {};
	let currentSection = "";
	try {
		const content = fs.readFileSync(filepath, "utf-8");
		for (const line of content.split("\n")) {
			const stripped = line.trim();
			if (!stripped || stripped.startsWith("#")) continue;
			const sectionMatch = stripped.match(/^\[(\S+)\]/);
			if (sectionMatch) {
				currentSection = sectionMatch[1];
				result[currentSection] = {};
				continue;
			}
			const kvMatch = stripped.match(/^(\S+)\s*=\s*(.+)$/);
			if (kvMatch && currentSection) {
				result[currentSection][kvMatch[1]] = kvMatch[2].trim().replace(/^["']|["']$/g, "");
			}
		}
	} catch { /* file may not exist */ }
	return result;
}

function parseAgentFrontmatter(content: string): { name: string; description: string; model: string } | null {
	const match = content.match(/^---\n([\s\S]*?)\n---/);
	if (!match) return null;
	const fm = match[1];
	let name = "", description = "", model = "";
	for (const line of fm.split("\n")) {
		const nm = line.match(/^name:\s*(.+)$/);
		if (nm) name = nm[1].trim();
		const dm = line.match(/^description:\s*["']?(.+?)["']?\s*$/);
		if (dm) description = dm[1].trim();
		const mm = line.match(/^model:\s*(.+)$/);
		if (mm) model = mm[1].trim();
	}
	if (!name) return null;
	return { name, description, model };
}

function parseSkillFrontmatter(content: string): { name: string; description: string } | null {
	const match = content.match(/^---\n([\s\S]*?)\n---/);
	if (!match) return null;
	const fm = match[1];
	let name = "", description = "";
	for (const line of fm.split("\n")) {
		const nm = line.match(/^name:\s*(.+)$/);
		if (nm) name = nm[1].trim();
		const dm = line.match(/^description:\s*["']?(.+?)["']?\s*$/);
		if (dm) description = dm[1].trim();
	}
	if (!name || !description) return null;
	return { name, description };
}

function loadAgents(): AgentMeta[] {
	const agentsDir = getAgentsDir();
	const modelsYml = getModelsYml();
	const roleMapYml = getRoleMapYml();
	const modelsData = parseSimpleYaml(modelsYml);
	const rolesData = parseSimpleYaml(roleMapYml);
	const roles = rolesData["roles"] || {};

	const agents: AgentMeta[] = [];
	try {
		const entries = fs.readdirSync(agentsDir).filter(f => f.endsWith(".md")).sort();
		for (const entry of entries) {
			const filePath = path.join(agentsDir, entry);
			const content = fs.readFileSync(filePath, "utf-8");
			const meta = parseAgentFrontmatter(content);
			if (!meta) continue;
			const category = meta.name.split("-")[0];
			const role = rolesData[meta.name] || "agentic-engineering";
			const model = roles[role] || meta.model;
			agents.push({ ...meta, category, role, model, filePath });
		}
	} catch { /* dir may not exist */ }
	return agents;
}

function loadSkills(): SkillMeta[] {
	const skillsDir = getSkillsDir();
	const skills: SkillMeta[] = [];
	try {
		const entries = fs.readdirSync(skillsDir).filter(f => {
			return fs.existsSync(path.join(skillsDir, f, "SKILL.md"));
		}).sort();
		for (const entry of entries) {
			const skillFile = path.join(skillsDir, entry, "SKILL.md");
			const content = fs.readFileSync(skillFile, "utf-8");
			const meta = parseSkillFrontmatter(content);
			if (!meta) continue;
			skills.push({ name: meta.name, description: meta.description, dir: entry });
		}
	} catch { /* dir may not exist */ }
	return skills;
}

function buildAgentCatalogText(): string {
	const agents = loadAgents();
	const lines: string[] = ["# Available Expert Agents\n"];
	for (const cat of CATEGORY_ORDER) {
		const catAgents = agents.filter(a => a.category === cat);
		if (catAgents.length === 0) continue;
		const label = CATEGORY_LABELS[cat] || cat;
		lines.push(`## ${label}\n`);
		for (const agent of catAgents) {
			lines.push(`- **${agent.name}** (${agent.role}) — ${agent.description}`);
		}
		lines.push("");
	}
	return lines.join("\n");
}

function buildModelsCatalogText(): string {
	const modelsYml = getModelsYml();
	const data = parseSimpleYaml(modelsYml);
	const roles = data["roles"] || {};
	const lines: string[] = ["# Model Catalog & Role Assignments\n"];
	lines.push("## Current Role → Model Mappings\n");
	for (const [role, model] of Object.entries(roles)) {
		lines.push(`- **${role}**: \`${model}\``);
	}
	lines.push("\n## Available Models\n");

	// Group models by tier
	const tierLabels: Record<string, string> = {
		"deepseek-v4-pro": "Frontier Reasoning",
		"kimi-k2.6": "Frontier Reasoning",
		"qwen3.5-397b": "Research",
		"glm-5.1": "Agentic Engineering",
		"deepseek-v4-flash": "Fast Reasoning",
		"qwen3-coder-next": "Code Specialist",
		"devstral-2-123b": "Large Edit",
		"minimax-m2.7": "Long Document",
		"gpt-oss-120b": "Balanced",
		"gpt-oss-20b": "Balanced",
		"gemini-3-flash-preview": "Multimodal",
		"qwen3-vl-235b": "Visual Reasoning",
		"gemma4-31b": "Lightweight Visual",
		"devstral-small-2": "Fast Coding",
		"nemotron-3-super": "Multi-Agent",
		"nemotron-3-nano-30b": "Quick Thinking",
		"rnj-1-8b": "Trivial",
	};

	for (const [key, modelData] of Object.entries(data)) {
		if (key === "roles") continue;
		if (!modelData.id) continue;
		const label = tierLabels[key] || "Other";
		const name = modelData.name || key;
		const ctx = modelData.context || "?";
		const maxTok = modelData.max_tokens || "?";
		const reasoning = modelData.reasoning === "true" ? "yes" : "no";
		lines.push(`### ${name} (${label})`);
		lines.push(`- ID: \`${modelData.id}\``);
		lines.push(`- Context: ${ctx} tokens | Output: ${maxTok} tokens | Reasoning: ${reasoning}`);
		if (modelData.strengths) {
			const strengths = Array.isArray(modelData.strengths) ? modelData.strengths : [modelData.strengths];
			lines.push(`- Strengths: ${strengths.join(", ")}`);
		}
		lines.push("");
	}
	return lines.join("\n");
}

function buildSkillCatalogText(): string {
	const skills = loadSkills();
	if (skills.length === 0) return "No skills found.";
	const lines: string[] = ["# Available Skills\n"];
	for (const skill of skills) {
		lines.push(`- **${skill.name}** — ${skill.description}`);
	}
	return lines.join("\n");
}

function runGitCommand(repoDir: string, args: string[]): string {
	try {
		return execSync(`git ${args.join(" ")}`, { cwd: repoDir, encoding: "utf-8", timeout: 30_000 }).trim();
	} catch (e: any) {
		return `ERROR: ${e.message || String(e)}`;
	}
}

export default function xpertExtension(pi: ExtensionAPI) {
	pi.registerCommand("xpert", {
		description: "Browse and activate expert agents, skills, and model catalog",
		handler: async (args, ctx) => {
			const arg = (args || "").trim().toLowerCase();

			if (arg === "list" || arg === "agents") {
				pi.sendMessage({
					customType: "xpert-catalog",
					content: buildAgentCatalogText(),
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify("Agent catalog loaded", "info");
				return;
			}

			if (arg === "skills") {
				pi.sendMessage({
					customType: "xpert-skills",
					content: buildSkillCatalogText(),
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify("Skill catalog loaded", "info");
				return;
			}

			if (arg === "models") {
				pi.sendMessage({
					customType: "xpert-models",
					content: buildModelsCatalogText(),
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify("Model catalog loaded", "info");
				return;
			}

			if (arg.startsWith("activate ")) {
				const agentName = arg.slice("activate ".length).trim();
				const agents = loadAgents();
				const agent = agents.find(a => a.name === agentName);
				if (!agent) {
					ctx.ui.notify(`Agent "${agentName}" not found. Use /xpert list to see available agents.`, "warning");
					return;
				}
				const content = fs.readFileSync(agent.filePath, "utf-8");
				const bodyMatch = content.match(/^---\n[\s\S]*?\n---\n([\s\S]*)$/);
				const body = bodyMatch ? bodyMatch[1] : content;
				pi.sendMessage({
					customType: "xpert-activate",
					content: `Activated expert agent: **${agent.name}** (${agent.role} → ${agent.model})\n\n${body.slice(0, 3000)}\n\n*(Full expertise loaded — use \`task\` with \`agent: "${agent.name}"\` to spawn this expert)*`,
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify(`Expert ${agent.name} activated (${agent.model})`, "info");
				return;
			}

			if (arg.startsWith("skill ")) {
				const skillName = arg.slice("skill ".length).trim();
				const skills = loadSkills();
				const skill = skills.find(s => s.name === skillName || s.dir === skillName);
				if (!skill) {
					ctx.ui.notify(`Skill "${skillName}" not found. Use /xpert skills to see available skills.`, "warning");
					return;
				}
				const skillFile = path.join(getSkillsDir(), skill.dir, "SKILL.md");
				const content = fs.readFileSync(skillFile, "utf-8");
				const bodyMatch = content.match(/^---\n[\s\S]*?\n---\n([\s\S]*)$/);
				const body = bodyMatch ? bodyMatch[1] : content;
				pi.sendMessage({
					customType: "xpert-skill-activate",
					content: `Activated skill: **${skill.name}**\n\n${body}`,
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify(`Skill ${skill.name} loaded into context`, "info");
				return;
			}

			// Default: show category selector
			const agents = loadAgents();
			const categories = CATEGORY_ORDER.filter(cat => agents.some(a => a.category === cat));

			if (categories.length === 0) {
				ctx.ui.notify("No expert agents found in ~/.omp/agent/agents/", "warning");
				return;
			}

			const categoryOptions = categories.map(cat => {
				const label = CATEGORY_LABELS[cat] || cat;
				const count = agents.filter(a => a.category === cat).length;
				return `${label} (${count})`;
			});

			const selected = await ctx.ui.select("Select expert category", categoryOptions);
			if (!selected) return;

			const selectedIndex = categoryOptions.indexOf(selected);
			if (selectedIndex === -1) return;
			const selectedCat = categories[selectedIndex];

			const catAgents = agents.filter(a => a.category === selectedCat);
			const agentOptions = catAgents.map(a => {
				const shortDesc = a.description.length > 80
					? a.description.slice(0, 77) + "..."
					: a.description;
				return `${a.name}: ${shortDesc}`;
			});

			const agentSelected = await ctx.ui.select(
				`${CATEGORY_LABELS[selectedCat]} — Select agent`,
				agentOptions,
			);
			if (!agentSelected) return;

			const agentIndex = agentOptions.indexOf(agentSelected);
			if (agentIndex === -1) return;
			const chosen = catAgents[agentIndex];

			const content = fs.readFileSync(chosen.filePath, "utf-8");
			const bodyMatch = content.match(/^---\n[\s\S]*?\n---\n([\s\S]*)$/);
			const body = bodyMatch ? bodyMatch[1] : content;

			pi.sendMessage({
				customType: "xpert-activate",
				content: `Activated expert agent: **${chosen.name}** (${chosen.role} → ${chosen.model}) — ${chosen.description}\n\nUse the task tool with \`agent: "${chosen.name}"\` to spawn this expert for delegated work.\n\n## ${chosen.name} Expertise\n\n${body.slice(0, 3000)}\n\n*(Full expertise loaded — reference skill://xpert/${chosen.name} for complete details)*`,
				display: true,
				attribution: "user",
			}, { triggerTurn: false });
			ctx.ui.notify(`Expert ${chosen.name} activated (${chosen.model})`, "info");
		},
	});

	pi.registerCommand("update-agents", {
		description: "Update agents from source repos, reconcile models from models.yml",
		handler: async (args, ctx) => {
			const subcmd = (args || "").trim().toLowerCase();

			if (subcmd === "reconcile") {
				ctx.ui.notify("Reconciling agent model assignments...", "info");
				try {
					// Run the reconcile script
					const scriptPath = path.join(path.dirname(new URL(import.meta.url).pathname)), "reconcile-agents.py");
					const result = execSync(
						`python3 ${path.join(os.homedir(), "Projects/Personal/omp-test/reconcile-agents.py")}`,
						{ encoding: "utf-8", timeout: 30_000 },
					);
					pi.sendMessage({
						customType: "xpert-update",
						content: `## Agent Model Reconciliation Complete\n\n\`\`\`\n${result}\n\`\`\``,
						display: true,
						attribution: "user",
					}, { triggerTurn: false });
				} catch (e: any) {
					ctx.ui.notify(`Reconciliation failed: ${e.message}`, "warning");
				}
				return;
			}

			if (subcmd === "check") {
				ctx.ui.notify("Checking for updates...", "info");
				const manifestPath = getManifestYml();
				const manifestData = parseSimpleYaml(manifestPath);

				const lines: string[] = ["## Source Repository Status\n"];

				for (const [sourceKey, sourceData] of Object.entries(manifestData)) {
					if (!sourceData.url) continue;
					const lastCommit = sourceData.commit || "unknown";
					const lastDate = sourceData.date || "unknown";
					lines.push(`### ${sourceKey}`);
					lines.push(`- URL: ${sourceData.url}`);
					lines.push(`- Last synced: ${lastDate} (${lastCommit.slice(0, 8)})`);
					lines.push(`- Agents: ${(sourceData.agents || []).length}`);
					lines.push(`- Skills: ${(sourceData.skills || []).length}`);
					lines.push("");
				}

				lines.push("To pull updates: `/update-agents pull`");
				lines.push("To reconcile models: `/update-agents reconcile`");

				pi.sendMessage({
					customType: "xpert-update",
					content: lines.join("\n"),
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				return;
			}

			// Default: show help
			pi.sendMessage({
				customType: "xpert-update",
				content: `## Update Commands\n\n- \`/update-agents check\` — Show source repo status\n- \`/update-agents pull\` — Pull changes and adapt agents\n- \`/update-agents reconcile\` — Rewrite agent frontmatter from models.yml\n- \`/update-skills check\` — Check for new skills\n- \`/update-skills pull\` — Pull and adapt new skills\n\n## Current Config\n\n- Models: \`${getModelsYml()}\`\n- Role map: \`${getRoleMapYml()}\`\n- Manifest: \`${getManifestYml()}\`\n- Agents: \`${getAgentsDir()}\`\n- Skills: \`${getSkillsDir()}\``,
				display: true,
				attribution: "user",
			}, { triggerTurn: false });
		},
	});

	pi.registerCommand("update-skills", {
		description: "Update skills from source repos",
		handler: async (args, ctx) => {
			const subcmd = (args || "").trim().toLowerCase();

			if (subcmd === "check") {
				ctx.ui.notify("Checking for skill updates...", "info");
				const manifestPath = getManifestYml();
				const manifestData = parseSimpleYaml(manifestPath);
				const composio = manifestData["sources.composio-skills"] || {};

				pi.sendMessage({
					customType: "xpert-update",
					content: `## Skill Sources\n\n### Composio Skills\n- URL: ${composio.url || "unknown"}\n- Last synced: ${composio.date || "unknown"}\n- Skills tracked: ${(composio.skills || []).length}\n\nTo pull updates: \`/update-skills pull\``,
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				return;
			}

			// Default: show help
			pi.sendMessage({
				customType: "xpert-update",
				content: `## Skill Update Commands\n\n- \`/update-skills check\` — Show source repo status\n- \`/update-skills pull\` — Pull and adapt new skills`,
				display: true,
				attribution: "user",
			}, { triggerTurn: false });
		},
	});

	pi.on("session_start", async (_event, ctx) => {
		const agents = loadAgents();
		const skills = loadSkills();
		ctx.ui.notify(
			`Xpert ready: ${agents.length} agents, ${skills.length} skills, ${new Set(agents.map(a => a.model)).size} models. Use /xpert to browse.`,
			"info",
		);
	});
}

