// ── Helpers ──────────────────────────────────────────────────────────

const AGENTS_DIR = path.join(os.homedir(), ".omp", "agent", "agents");
const SKILLS_DIR = path.join(os.homedir(), ".omp", "agent", "skills");
const CONFIG_PATH = path.join(os.homedir(), ".omp", "agent", "config.yml");

interface AgentInfo {
	name: string;
	description: string;
	category: string;
	model: string;
	filePath: string;
}

interface SkillInfo {
	name: string;
	description: string;
	dir: string;
}

function parseYamlConfig(content: string): Record<string, unknown> {
	try { return (yaml.load(content) as Record<string, unknown>) || {}; }
	catch { return {}; }
}

function stringifyYamlConfig(config: Record<string, unknown>): string {
	return yaml.dump(config, { lineWidth: -1, noRefs: true });
}

function getDisabledAgents(): Set<string> {
	try {
		const content = fs.readFileSync(CONFIG_PATH, "utf-8");
		const config = parseYamlConfig(content);
		const task = (config.task || {}) as Record<string, unknown>;
		const list = (task.disabledAgents || []) as string[];
		return new Set(list);
	} catch {
		return new Set();
	}
}

function setDisabledAgents(disabled: Set<string>): void {
	const content = fs.readFileSync(CONFIG_PATH, "utf-8");
	const config = parseYamlConfig(content);
	const task = ((config.task || {}) as Record<string, unknown>);
	task.disabledAgents = Array.from(disabled).sort();
	config.task = task;
	fs.writeFileSync(CONFIG_PATH, stringifyYamlConfig(config), "utf-8");
}

function loadAgents(): AgentInfo[] {
	const agents: AgentInfo[] = [];
	try {
		const entries = fs.readdirSync(AGENTS_DIR).filter(f => f.endsWith(".md")).sort();
		for (const entry of entries) {
			const filePath = path.join(AGENTS_DIR, entry);
			const content = fs.readFileSync(filePath, "utf-8");
			const fmMatch = content.match(/^---\n([\s\S]*?)\n---/);
			if (!fmMatch) continue;
			const fm = fmMatch[1];
			let name = "", description = "", model = "";
			for (const line of fm.split("\n")) {
				const nm = line.match(/^name:\s*(.+)$/);
				if (nm) name = nm[1].trim();
				const dm = line.match(/^description:\s*["']?(.+?)["']?\s*$/);
				if (dm) description = dm[1].trim();
				const mm = line.match(/^model:\s*(.+)$/);
				if (mm) model = mm[1].trim();
			}
			if (!name) continue;
			const category = name.split("-")[0];
			agents.push({ name, description, category, model, filePath });
		}
	} catch { /* dir may not exist */ }
	return agents;
}

function loadSkills(): SkillInfo[] {
	const skills: SkillInfo[] = [];
	try {
		const entries = fs.readdirSync(SKILLS_DIR).filter(d => {
			return fs.existsSync(path.join(SKILLS_DIR, d, "SKILL.md"));
		}).sort();
		for (const entry of entries) {
			const skillFile = path.join(SKILLS_DIR, entry, "SKILL.md");
			const content = fs.readFileSync(skillFile, "utf-8");
			const fmMatch = content.match(/^---\n([\s\S]*?)\n---/);
			if (!fmMatch) continue;
			const fm = fmMatch[1];
			let name = "", description = "";
			for (const line of fm.split("\n")) {
				const nm = line.match(/^name:\s*(.+)$/);
				if (nm) name = nm[1].trim();
				const dm = line.match(/^description:\s*["']?(.+?)["']?\s*$/);
				if (dm) description = dm[1].trim();
			}
			if (!name) continue;
			skills.push({ name, description, dir: entry });
		}
	} catch { /* dir may not exist */ }
	return skills;
}

function renderTeamStatus(team: Team, disabled: Set<string>, agents: AgentInfo[]): string {
	const lines: string[] = [];
	let activeCount = 0;

	for (const agentId of team.agents) {
		const isDisabled = disabled.has(agentId);
		const agent = agents.find(a => a.name === agentId);
		const status = isDisabled ? "✗" : "✓";
		const modelLabel = agent ? agent.model.split("/").pop() || agent.model : "?";
		const desc = agent ? (agent.description.length > 60 ? agent.description.slice(0, 57) + "..." : agent.description) : "unknown";
		if (!isDisabled) activeCount++;
		lines.push(`  ${status} ${agentId.padEnd(38)} ${modelLabel}`);
		if (agent) lines.push(`    ${desc}`);
	}

	const skillLines = team.skills.length > 0
		? team.skills.map(s => `  ◆ ${s}`).join("\n")
		: "  (none)";

	return [
		`${team.emoji} ${team.label} — ${activeCount}/${team.agents.length} active`,
		`${team.description}`,
		"",
		"Agents:",
		...lines,
		"",
		"Paired skills:",
		skillLines,
	].join("\n");
}

function renderAllTeamsStatus(disabled: Set<string>, agents: AgentInfo[]): string {
	const lines: string[] = ["Team Activation Status", "═".repeat(60), ""];

	for (const team of TEAMS) {
		const activeCount = team.agents.filter(id => !disabled.has(id)).length;
		const total = team.agents.length;
		const bar = "█".repeat(activeCount) + "░".repeat(total - activeCount);
		const status = activeCount === 0 ? "OFF " : activeCount === total ? "ON  " : "PART";
		lines.push(`${team.emoji} ${status} [${bar}] ${activeCount}/${total} ${team.label}`);
	}

	lines.push("");
	lines.push("Use /xpert to browse teams, /xpert on <team> to activate, /xpert off <team> to deactivate");
	return lines.join("\n");
}

function renderAllAgentsList(disabled: Set<string>, agents: AgentInfo[]): string {
	const lines: string[] = ["Agent Catalog", "═".repeat(60), ""];

	const byCategory = new Map<string, AgentInfo[]>();
	for (const agent of agents) {
		const cat = agent.category;
		if (!byCategory.has(cat)) byCategory.set(cat, []);
		byCategory.get(cat)!.push(agent);
	}

	const CATEGORY_LABELS: Record<string, string> = {
		phd: "PhD Research Assistants",
		dev: "Core Development",
		lang: "Language Specialists",
		infra: "Infrastructure",
		qual: "Quality & Security",
		data: "Data & AI",
		dx: "Developer Experience",
		spec: "Specialized Domains",
		biz: "Business & Product",
		meta: "Meta-Orchestration",
		res: "Research & Analysis",
	};

	const order = ["phd", "dev", "lang", "infra", "qual", "data", "dx", "spec", "biz", "meta", "res"];
	for (const cat of order) {
		const catAgents = byCategory.get(cat);
		if (!catAgents || catAgents.length === 0) continue;
		const label = CATEGORY_LABELS[cat] || cat;
		lines.push(`\n## ${label} (${catAgents.length})`);
		for (const agent of catAgents) {
			const status = disabled.has(agent.name) ? "✗" : "✓";
			lines.push(`  ${status} ${agent.name}`);
		}
	}

	return lines.join("\n");
}

// ── Extension ────────────────────────────────────────────────────────

export default function xpertExtension(pi: ExtensionAPI) {
	pi.registerCommand("xpert", {
		description: "Team-based expert agent browser and manager — activate teams of agents by preset",
		handler: async (args, ctx) => {
			const arg = (args || "").trim().toLowerCase();
			const agents = loadAgents();
			const skills = loadSkills();
			const disabled = getDisabledAgents();

			// ── /xpert status ──────────────────────────────────────────
			if (arg === "status" || arg === "teams") {
				pi.sendMessage({
					customType: "xpert-status",
					content: renderAllTeamsStatus(disabled, agents),
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify("Team status loaded", "info");
				return;
			}

			// ── /xpert list ────────────────────────────────────────────
			if (arg === "list" || arg === "agents") {
				pi.sendMessage({
					customType: "xpert-catalog",
					content: renderAllAgentsList(disabled, agents),
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify("Agent catalog loaded", "info");
				return;
			}

			// ── /xpert skills ─────────────────────────────────────────
			if (arg === "skills") {
				const lines = skills.map(s => `  ◆ ${s.name} — ${s.description}`);
				pi.sendMessage({
					customType: "xpert-skills",
					content: `Available Skills (${skills.length})\n${"═".repeat(60)}\n\n${lines.join("\n")}`,
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify("Skill catalog loaded", "info");
				return;
			}

			// ── /xpert models ──────────────────────────────────────────
			if (arg === "models") {
				const modelsYml = path.join(os.homedir(), ".omp", "agent", "models.yml");
				let content: string;
				try { content = fs.readFileSync(modelsYml, "utf-8"); } catch { content = "models.yml not found"; }
				pi.sendMessage({
					customType: "xpert-models",
					content: `# Model Catalog\n\n\`\`\`yaml\n${content}\n\`\`\``,
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify("Model catalog loaded", "info");
				return;
			}

			// ── /xpert on <team-id> ────────────────────────────────────
			if (arg.startsWith("on ")) {
				const teamId = arg.slice(3).trim();
				const team = TEAMS.find(t => t.id === teamId);
				if (!team) {
					ctx.ui.notify(`Unknown team: "${teamId}". Available: ${TEAMS.map(t => t.id).join(", ")}`, "warning");
					return;
				}
				const currentDisabled = getDisabledAgents();
				for (const agentId of team.agents) {
					currentDisabled.delete(agentId);
				}
				setDisabledAgents(currentDisabled);
				const activeCount = team.agents.filter(id => !currentDisabled.has(id)).length;
				pi.sendMessage({
					customType: "xpert-activate",
					content: `${team.emoji} Activated **${team.label}** — ${activeCount}/${team.agents.length} agents enabled.\n\n${renderTeamStatus(team, currentDisabled, agents)}\n\nPaired skills: ${team.skills.map(s => `skill://${s}`).join(", ") || "none"}\n\nRun \`/xpert\` to see team status, or start using the agents with \`task\`.`,
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify(`${team.label} activated (${activeCount} agents)`, "info");
				return;
			}

			// ── /xpert off <team-id> ───────────────────────────────────
			if (arg.startsWith("off ")) {
				const teamId = arg.slice(3).trim();
				const team = TEAMS.find(t => t.id === teamId);
				if (!team) {
					ctx.ui.notify(`Unknown team: "${teamId}". Available: ${TEAMS.map(t => t.id).join(", ")}`, "warning");
					return;
				}
				const currentDisabled = getDisabledAgents();
				for (const agentId of team.agents) {
					currentDisabled.add(agentId);
				}
				setDisabledAgents(currentDisabled);
				pi.sendMessage({
					customType: "xpert-deactivate",
					content: `${team.emoji} Deactivated **${team.label}** — all ${team.agents.length} agents disabled.`,
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify(`${team.label} deactivated`, "info");
				return;
			}

			// ── /xpert toggle <prefix> ─────────────────────────────────
			if (arg.startsWith("toggle ")) {
				const prefix = arg.slice(6).trim();
				const currentDisabled = getDisabledAgents();
				const matchingAgents = agents.filter(a => a.name.startsWith(prefix + "-"));
				if (matchingAgents.length === 0) {
					ctx.ui.notify(`No agents with prefix "${prefix}-"`, "warning");
					return;
				}
				const allDisabled = matchingAgents.every(a => currentDisabled.has(a.name));
				for (const agent of matchingAgents) {
					if (allDisabled) {
						currentDisabled.delete(agent.name);
					} else {
						currentDisabled.add(agent.name);
					}
				}
				setDisabledAgents(currentDisabled);
				const action = allDisabled ? "Activated" : "Deactivated";
				const count = matchingAgents.length;
				pi.sendMessage({
					customType: "xpert-toggle",
					content: `${action} ${count} agents with prefix \`${prefix}-\`.\n\n${matchingAgents.map(a => `${allDisabled ? "✓" : "✗"} ${a.name}`).join("\n")}`,
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify(`${action} ${count} agents (${prefix}-*)`, "info");
				return;
			}

			// ── /xpert (interactive) ──────────────────────────────────
			// Show team overview, then let user select a team
			const statusLines = TEAMS.map(team => {
				const activeCount = team.agents.filter(id => !disabled.has(id)).length;
				const total = team.agents.length;
				const bar = "█".repeat(activeCount) + "░".repeat(total - activeCount);
				const status = activeCount === 0 ? "OFF " : activeCount === total ? "ON  " : "PART";
				return `${status} [${bar}] ${team.emoji} ${team.label} (${activeCount}/${total})`;
			});

			pi.sendMessage({
				customType: "xpert-overview",
				content: `# Expert Team Browser\n\nActivate teams of agents by preset — much faster than toggling individually.\n\n${statusLines.join("\n")}\n\nSelect a team below to view details and activate/deactivate.`,
				display: true,
				attribution: "user",
			}, { triggerTurn: false });

			const options = [
				...TEAMS.map(team => {
					const activeCount = team.agents.filter(id => !disabled.has(id)).length;
					const total = team.agents.length;
					return `${team.emoji} ${team.label} (${activeCount}/${total})`;
				}),
				"📊 Full status",
				"📋 All agents list",
			];

			const selected = await ctx.ui.select("Select a team to manage", options);
			if (!selected) return;

			if (selected === "📊 Full status") {
				pi.sendMessage({
					customType: "xpert-status",
					content: renderAllTeamsStatus(getDisabledAgents(), agents),
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				return;
			}

			if (selected === "📋 All agents list") {
				pi.sendMessage({
					customType: "xpert-catalog",
					content: renderAllAgentsList(getDisabledAgents(), agents),
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				return;
			}

			// Find the team
			const teamIndex = options.indexOf(selected);
			if (teamIndex < 0 || teamIndex >= TEAMS.length) return;
			const team = TEAMS[teamIndex];

			// Show team details
			pi.sendMessage({
				customType: "xpert-team-detail",
				content: renderTeamStatus(team, getDisabledAgents(), agents),
				display: true,
				attribution: "user",
			}, { triggerTurn: false });

			const currentDisabled = getDisabledAgents();
			const activeCount = team.agents.filter(id => !currentDisabled.has(id)).length;
			const isFullyActive = activeCount === team.agents.length;
			const isFullyInactive = activeCount === 0;

			const actions = [];
			if (!isFullyActive) actions.push("✓ Activate all");
			if (!isFullyInactive) actions.push("✗ Deactivate all");
			actions.push("← Back to teams");
			actions.push("🔍 View agent details");

			const action = await ctx.ui.select(`${team.emoji} ${team.label} — Choose action`, actions);
			if (!action) return;

			if (action === "✓ Activate all") {
				const d = getDisabledAgents();
				for (const agentId of team.agents) d.delete(agentId);
				setDisabledAgents(d);
				pi.sendMessage({
					customType: "xpert-activate",
					content: `${team.emoji} **${team.label}** activated! All ${team.agents.length} agents enabled.\n\nPaired skills: ${team.skills.map(s => `skill://${s}`).join(", ") || "none"}\n\nUse these agents with \`task\` — they will appear as available subagents.`,
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify(`${team.label} activated`, "info");
				return;
			}

			if (action === "✗ Deactivate all") {
				const d = getDisabledAgents();
				for (const agentId of team.agents) d.add(agentId);
				setDisabledAgents(d);
				pi.sendMessage({
					customType: "xpert-deactivate",
					content: `${team.emoji} **${team.label}** deactivated. All ${team.agents.length} agents disabled.`,
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				ctx.ui.notify(`${team.label} deactivated`, "info");
				return;
			}

			if (action === "🔍 View agent details") {
				const agentLines = team.agents.map(id => {
					const agent = agents.find(a => a.name === id);
					if (!agent) return `  ${id} (not found)`;
					const status = currentDisabled.has(id) ? "✗" : "✓";
					const modelLabel = agent.model.split("/").pop() || agent.model;
					return `  ${status} ${id} (${modelLabel})\n     ${agent.description}`;
				});
				pi.sendMessage({
					customType: "xpert-agent-details",
					content: `${team.emoji} ${team.label} — Agent Details\n\n${agentLines.join("\n")}\n\nPaired skills: ${team.skills.map(s => `skill://${s}`).join(", ") || "none"}`,
					display: true,
					attribution: "user",
				}, { triggerTurn: false });
				return;
			}

			// "← Back to teams" or cancelled — do nothing
		},
	});

	pi.on("session_start", async (_event, ctx) => {
		const agents = loadAgents();
		const skills = loadSkills();
		const disabled = getDisabledAgents();
		const activeTeams = TEAMS.filter(team => team.agents.some(id => !disabled.has(id)));
		const teamSummary = activeTeams.length > 0
			? activeTeams.map(t => t.emoji + " " + t.label).join(", ")
			: "none";
		ctx.ui.notify(
			`Xpert: ${activeTeams.length}/${TEAMS.length} teams active (${teamSummary}). Use /xpert to manage.`,
			"info",
		);
	});
}

