import * as fs from 'node:fs';

const CONFIG_PATH = '/home/jpolo/.omp/agent/config.yml';

function getDisabledAgents(): Set<string> {
  const content = fs.readFileSync(CONFIG_PATH, 'utf-8');
  const agents = new Set<string>();
  let inDisabled = false;
  for (const line of content.split('\n')) {
    if (line.match(/^  disabledAgents:/)) { inDisabled = true; continue; }
    if (inDisabled) {
      const m = line.match(/^    - (.+)$/);
      if (m) agents.add(m[1].trim());
      else if (!line.match(/^    /) && !line.match(/^    #/)) { inDisabled = false; }
    }
  }
  return agents;
}

function setDisabledAgents(disabled: Set<string>): void {
  const content = fs.readFileSync(CONFIG_PATH, 'utf-8');
  const lines = content.split('\n');
  const result: string[] = [];
  let inDisabled = false;
  let disabledWritten = false;

  for (const line of lines) {
    if (line.match(/^  disabledAgents:/)) {
      inDisabled = true;
      disabledWritten = false;
      result.push(line);
      // Write new list
      const sorted = Array.from(disabled).sort();
      result.push('    # All custom agents disabled — activate on-demand via /xpert');
      for (const agent of sorted) {
        result.push('    - ' + agent);
      }
      continue;
    }
    if (inDisabled) {
      // Skip old disabled agent lines
      if (line.match(/^    - /) || line.match(/^    #/)) continue;
      // We've reached the end of the disabled list
      inDisabled = false;
    }
    result.push(line);
  }

  fs.writeFileSync(CONFIG_PATH, result.join('\n'), 'utf-8');
}

